mapper.select:
select category_id as categoryId, category_code as categoryCode, category_name as categoryName, icon, sort, disabled_flag as disabledFlag, remark, create_time as createTime, update_time as updateTime from t_bpm_category where deleted_flag = #{queryForm.deletedFlag}
and category_code like concat('%', #{queryForm.categoryCode}, '%')
and category_name like concat('%', #{queryForm.categoryName}, '%')
and disabled_flag = #{queryForm.disabledFlag}
order by sort asc, category_id desc

select *
from t_bpm_category
where 1 = 1

    and category_id = #{categoryId}


    and category_code = #{categoryCode}


    and deleted_flag = #{deletedFlag}

limit 1
